import{_ as s,o as a,c as l,R as p}from"./chunks/framework.107209bd.js";const m=JSON.parse('{"title":"1.解释下spa的原理 及 spa路由模式","description":"","frontmatter":{},"headers":[],"relativePath":"面试八股文/vue/1.解释下spa的原理.md","filePath":"面试八股文/vue/1.解释下spa的原理.md","lastUpdated":null}'),t={name:"面试八股文/vue/1.解释下spa的原理.md"},n=p(`<h1 id="_1-解释下spa的原理-及-spa路由模式" tabindex="-1">1.解释下spa的原理 及 spa路由模式 <a class="header-anchor" href="#_1-解释下spa的原理-及-spa路由模式" aria-label="Permalink to &quot;1.解释下spa的原理 及 spa路由模式&quot;">​</a></h1><blockquote><p>参考：SPA 路由三部曲之核心原理 作者：京东设计中心JDC-杨小璐 <a href="https://mp.weixin.qq.com/s/I0Wgcy1jYvu5HIAW9BKQuQ" target="_blank" rel="noreferrer">链接</a></p></blockquote><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>SPA就是单页WEB应用。SPA离不开前端路由的支持。</p><h2 id="前端路由的发展" tabindex="-1">前端路由的发展 <a class="header-anchor" href="#前端路由的发展" aria-label="Permalink to &quot;前端路由的发展&quot;">​</a></h2><p>既然说到了前端路由，就要回溯下它的发展史</p><h3 id="后端路由" tabindex="-1">后端路由 <a class="header-anchor" href="#后端路由" aria-label="Permalink to &quot;后端路由&quot;">​</a></h3><p>早期，路由是后端的概念，页面渲染完全依靠服务器。用户进行页面切换的时候，浏览器发送不同的URL请求，通过解析不同的URL地址进行路由匹配，模板拼接好后将HTML字符串返回给前端，浏览器拿到HTML字符串后就交给浏览器解析展示，这也就是所谓的服务端渲染。</p><img src="https://mmbiz.qpic.cn/mmbiz_png/MrFJyDNenF9zvqVaK9WxL3zSb5DVZ1YLSJC9btYCkNyoISdNOeJ2CThTicObJDJVdlBiacj62DxUOu3rQ9kKtqoQ/640?wx_fmt=png&amp;tp=wxpic&amp;wxfrom=5&amp;wx_lazy=1&amp;wx_co=1"><ul><li>优点：后端有完整的HTML代码，爬虫更容易获取信息，有利于SEO；对于客户端的资源占用更少</li><li>缺点：每跳转到不同的 URL都会重新访问服务器,给服务端增加压力;没有合理地利用缓存。</li></ul><h3 id="过渡方案ajax" tabindex="-1">过渡方案AJAX <a class="header-anchor" href="#过渡方案ajax" aria-label="Permalink to &quot;过渡方案AJAX&quot;">​</a></h3><p>AJAX是浏览器实现异步加载的一种技术方案。</p><h3 id="前端路由" tabindex="-1">前端路由 <a class="header-anchor" href="#前端路由" aria-label="Permalink to &quot;前端路由&quot;">​</a></h3><p>前端路由的特点就是在不完全刷新页面的情况下进行使徒的切换，页面的URL变了，但并没有重新加载。 前端路由使页面渲染由服务器渲染变为了前端渲染，请求一个URL时，服务端返回的是一个空的HTML</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;!</span><span style="color:#F07178;">DOCTYPE</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">html</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">html</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">head</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">meta</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">charset</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">UTF-8</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">title</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">Demo</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">title</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">link</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">app.css</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">rel</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">stylesheet</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">head</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">body</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">app</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">  &lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text/javascript</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">src</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">app.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">body</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">html</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><p>我们看到的页面是通过js渲染出来的</p><img src="https://mmbiz.qpic.cn/mmbiz_png/MrFJyDNenF9zvqVaK9WxL3zSb5DVZ1YLleWeCgY6FjRXdetmHRKEUDiaDE2ia3RIQc3BwYiacEbkPAyZVIE5RyudQ/640?wx_fmt=png&amp;tp=wxpic&amp;wxfrom=5&amp;wx_lazy=1&amp;wx_co=1"><ul><li>优点：缓解服务端压力；</li><li>缺点: 渲染速度不如服务端渲染；不利于SEO优化</li></ul><h2 id="前端路由核心原理" tabindex="-1">前端路由核心原理 <a class="header-anchor" href="#前端路由核心原理" aria-label="Permalink to &quot;前端路由核心原理&quot;">​</a></h2><p>前端路由的展示方式有 2 种：</p><ul><li>带有hash的前端路由：地址栏 URL 中有 #，即 hash 值，不好看，但兼容性高。</li><li>不带hash的前端路由：地址栏 URL 中没有 #，好看，但部分浏览器不支持，还需要后端服务器支持。</li></ul><p><strong>原理：本质上就是通过监测URL的变化，截获URL地址，通过解析、匹配路由规则实现UI更新</strong></p><h3 id="hash" tabindex="-1">hash <a class="header-anchor" href="#hash" aria-label="Permalink to &quot;hash&quot;">​</a></h3><p>一个完整的URL包括：协议、域名、端口、虚拟目录、文件名、参数、锚。</p><img src="https://mmbiz.qpic.cn/mmbiz_png/MrFJyDNenF9zvqVaK9WxL3zSb5DVZ1YLE7h4HZYRWGMtpsIg7S3G6lz5rNfpQXzQFKDUKgdguq55C9ePaz2m0w/640?wx_fmt=png&amp;tp=wxpic&amp;wxfrom=5&amp;wx_lazy=1&amp;wx_co=1"><p>hash值指的是URL地址中的锚部分，也就是#部分。hash也称为锚点，用来做页面定位的。</p><p>hash值更新有以下几个特点：</p><ul><li>hash值是网页的标志位，HTTP请求不包含锚部分，对后端没有影响</li><li>因为 HTTP 请求不包含锚部分，所以 hash 值改变时，不触发网页重载</li><li>改变 hash 值会改变浏览器的历史记录</li><li>改变 hash 值会触发 window.onhashchange() 事件</li></ul><p>改变hash值有以下几种方式</p><ul><li>通过a标签跳转</li><li>通过设置window.location.hash</li><li>浏览器前进（history.forword）后退(history.back)</li></ul><p><strong>hash模式路由就是利用onhashchange事件监听URL的变化，从而触发DOM操作来模拟页面跳转</strong></p><img src="https://mmbiz.qpic.cn/mmbiz_png/MrFJyDNenF9zvqVaK9WxL3zSb5DVZ1YLSHH00usG2TC2hdEIEJ60JmiboUG5icicTmuLb2Vyf5zptEtLabn582Liaw/640?wx_fmt=png&amp;tp=wxpic&amp;wxfrom=5&amp;wx_lazy=1&amp;wx_co=1"><h3 id="history" tabindex="-1">history <a class="header-anchor" href="#history" aria-label="Permalink to &quot;history&quot;">​</a></h3><p>浏览器有一个类似栈的历史记录，遵循先进后出的规则。URL的每次改变，包括hash值的改变都会在浏览器中形成一条历史记录。window对象通过history对象提供对浏览器历史记录的访问能力。</p><ul><li>history.lengh:出于安全考虑，History对象不允许未授权代码访问历史记录中其他页面的URLS，但可以通过history.length访问历史记录对象的长度。</li><li>history.back()：返回上一个历史记录，类似浏览器的后退按钮</li><li>history.forward(): 前进到下一个历史记录，类似浏览器前进按钮</li><li>history.go(n): 跳转到相应的访问记录，n &gt; 0，则前进，n &lt; 0，则后退</li></ul><p>为了配合单页应用的发展，HTML5对history API新增了两个方法</p><ul><li><p>pushState(state, title, URL)</p><ul><li>state: 用于存储该URL对应的状态对象，通过history.state获取</li><li>title：标题，不支持🈲</li><li>url：定义新的历史 URL 记录，需要注意，新的 URL 必须与当前 URL 同源，不能跨域。 <strong>TIPS：</strong> pushState 函数会向浏览器的历史记录中添加一条，history.length 的值会 +1，当前浏览器的 URL 变成了新的 URL。<strong>它仅仅将浏览器的 URL 变成了新的 URL，页面不会加载、刷新。</strong></li></ul></li><li><p>replaceState(state,title, URL) replaceState 的使用与 pushState 非常相似，都是改变当前的 URL，页面不刷新。<strong>区别在于 replaceState 是修改了当前的历史记录项而不是新建一个，history.length 的值保持不变。</strong></p></li></ul><h4 id="onpopstate" tabindex="-1">onpopstate() <a class="header-anchor" href="#onpopstate" aria-label="Permalink to &quot;onpopstate()&quot;">​</a></h4><p>通过pushState和replaceState改变的历史记录，点击浏览器的前进后退页面是没有反应的，为了配合上述两个API，HTML5还新增了一个事件，用于监听URL历史记录的改变：<code>window.onpopstate()</code></p>`,39),o=[n];function e(r,c,i,h,D,F){return a(),l("div",null,o)}const u=s(t,[["render",e]]);export{m as __pageData,u as default};
